"""
modules/supply_chain_geopolitics.py — ProQuant Capital | Tedarik Zinciri & Jeopolitik v11.0
==========================================================================================
Küresel liman krizleri, savaş senaryoları ve gemicilik rotalarındaki darboğazların 
(bottlenecks) emtia fiyatları üzerindeki şok dalgalarını tahminleyen simülatör.
Author: ProQuant Capital Global Macro Strategy | Version: 11.0.0
"""
class SupplyChainGeopoliticsModel:
    def calculate_shipping_delay_impact(self, delay_days: int, cargo_value: float, elasticity: float) -> float:
        """Gecikmelerin değer kaybı ve maliyet şoku etkisi."""
        return cargo_value * (delay_days * 0.001) * elasticity

